import threading
from collections import deque

class BoundedBlockingQueue:
    def __init__(self, capacity: int):
        self.buffer = deque()
        self.capacity = capacity
        self.lock = threading.Lock()
        self.not_full = threading.Condition(self.lock)
        self.not_empty = threading.Condition(self.lock)

    def put(self, item):
        with self.not_full:
            while len(self.buffer) >= self.capacity:
                self.not_full.wait()  # release lock, sleep until space
            self.buffer.append(item)
            self.not_empty.notify()  # wake a consumer

    def get(self):
        with self.not_empty:
            while not self.buffer:
                self.not_empty.wait()  # release lock, sleep until item
            item = self.buffer.popleft()
            self.not_full.notify()  # wake a producer
            return item

# Usage
queue = BoundedBlockingQueue(5)

def producer_func():
    for i in range(10): queue.put(f'item_{i}')

def consumer_func():
    for _ in range(10): print(queue.get())

p = threading.Thread(target=producer_func)
c = threading.Thread(target=consumer_func)
p.start(); c.start()
p.join(); c.join()

from concurrent.futures import ThreadPoolExecutor, as_completed

# Python Thread Pool
def process_task(task_id: int) -> str:
    # simulate work
    import time; time.sleep(0.1)
    return f'Task {task_id} done'

# Pool with 4 workers, submit 20 tasks
with ThreadPoolExecutor(max_workers=4) as executor:
    futures = [executor.submit(process_task, i) for i in range(20)]
    for future in as_completed(futures):
        print(future.result())  # waits for each as they complete

# With timeout
try:
    result = executor.submit(process_task, 99).result(timeout=5.0)
except TimeoutError:
    print('Task timed out')

