# Deadlock detection via wait-for graph
# Node per process, edge P_i → P_j means P_i waits for resource held by P_j
# Cycle in graph = deadlock

from collections import defaultdict, deque

def has_cycle(graph: dict) -> bool:
    """DFS cycle detection in directed graph"""
    visited, in_stack = set(), set()

    def dfs(node) -> bool:
        visited.add(node); in_stack.add(node)
        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                if dfs(neighbor): return True
            elif neighbor in in_stack: return True
        in_stack.discard(node)
        return False

    return any(dfs(n) for n in graph if n not in visited)

# Example: P0 waits for P1, P1 waits for P2, P2 waits for P0 → cycle!
wait_for = {0: [1], 1: [2], 2: [0]}
print(has_cycle(wait_for))  # True → deadlock!

